import { type ClassValue, clsx } from "clsx";
import { twMerge } from "tailwind-merge";

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

/**
 * Glassmorphism customization utilities
 * Allows users to customize color, transparency, blur, and outline for glass effects
 */

export interface GlassCustomization {
  /**
   * Background color for the glass effect (e.g., "oklch(100% 0 0 / 0.1)")
   * Default: uses CSS variable --glass-bg
   */
  color?: string;

  /**
   * Transparency/opacity for the background (0-1)
   * If provided, will override the alpha channel in color
   */
  transparency?: number;

  /**
   * Blur amount in pixels
   * Default: uses CSS variable --blur (20px)
   */
  blur?: number | string;

  /**
   * Border/outline color (e.g., "oklch(100% 0 0 / 0.25)")
   * Default: uses CSS variable --glass-border
   */
  outline?: string;

  /**
   * Border/outline width in pixels
   * Default: 1px
   */
  outlineWidth?: number | string;

  /**
   * Shadow for the glass effect
   * Default: uses CSS variable --glass-shadow
   */
  shadow?: string;

  /**
   * Inner glow color and intensity (e.g., "oklch(100% 0 0 / 0.2)")
   * Creates an inset shadow for a glowing effect inside the element
   */
  innerGlow?: string;

  /**
   * Inner glow blur/spread radius in pixels
   * Default: 20px
   */
  innerGlowBlur?: number | string;
}

/**
 * Set or replace the alpha channel on any CSS color string.
 * Handles oklch(), hex, and rgb/rgba formats — always outputs oklch.
 */
function setAlpha(color: string, alpha: number): string {
  // oklch(...) — replace or append alpha
  const oklchMatch = color.match(/^oklch\(([^/)]+?)(?:\s*\/\s*[\d.]+)?\)$/);
  if (oklchMatch) {
    return `oklch(${oklchMatch[1].trim()} / ${alpha})`;
  }

  // hex — convert to oklch with alpha
  if (color.startsWith("#")) {
    const hex = color.replace("#", "");
    const r = parseInt(hex.substring(0, 2), 16) / 255;
    const g = parseInt(hex.substring(2, 4), 16) / 255;
    const b = parseInt(hex.substring(4, 6), 16) / 255;
    // Approximate lightness for simple hex fallback
    const l = 0.2126 * r + 0.7152 * g + 0.0722 * b;
    return `oklch(${(l * 100).toFixed(1)}% 0 0 / ${alpha})`;
  }

  // rgb/rgba — convert to oklch with alpha
  const rgbaMatch = color.match(/rgba?\((\d+),\s*(\d+),\s*(\d+)/);
  if (rgbaMatch) {
    const l = (0.2126 * +rgbaMatch[1] + 0.7152 * +rgbaMatch[2] + 0.0722 * +rgbaMatch[3]) / 255;
    return `oklch(${(l * 100).toFixed(1)}% 0 0 / ${alpha})`;
  }

  // Unknown format — wrap with color-mix as fallback
  return `color-mix(in oklch, ${color} ${Math.round(alpha * 100)}%, transparent)`;
}

/**
 * Converts glass customization props to CSS style object
 */
export function getGlassStyles(customization?: GlassCustomization): React.CSSProperties {
  if (!customization) return {};

  const styles: React.CSSProperties = {};

  // Handle background color and transparency
  if (customization.color || customization.transparency !== undefined) {
    let bgColor = customization.color || "oklch(100% 0 0 / 0.1)";

    if (customization.transparency !== undefined) {
      bgColor = setAlpha(bgColor, customization.transparency);
    }

    styles.backgroundColor = bgColor;
  }

  // Handle blur
  if (customization.blur !== undefined) {
    const blurValue = typeof customization.blur === "number" ? `${customization.blur}px` : customization.blur;
    styles.backdropFilter = `blur(${blurValue})`;
    styles.WebkitBackdropFilter = `blur(${blurValue})`; // Safari support
  }

  // Handle outline/border - always apply border for glassmorphism effect
  if (customization.outline !== undefined) {
    const width = customization.outlineWidth || "1px";
    styles.borderColor = customization.outline;
    styles.borderWidth = typeof width === "number" ? `${width}px` : width;
    styles.borderStyle = "solid";
  } else if (!customization.outline && (customization.color || customization.transparency !== undefined || customization.blur !== undefined)) {
    // Apply default border if glass customization is provided but outline is not
    styles.borderColor = "oklch(100% 0 0 / 0.3)";
    styles.borderWidth = "1px";
    styles.borderStyle = "solid";
  }

  // Handle shadow and inner glow - combine both if provided
  const shadows: string[] = [];

  // Add outer shadow
  if (customization.shadow !== undefined) {
    shadows.push(customization.shadow);
  } else if (customization.color || customization.transparency !== undefined || customization.blur !== undefined) {
    // Apply default glass shadow for depth
    shadows.push("0 8px 32px oklch(0% 0 0 / 0.1), 0 2px 8px oklch(0% 0 0 / 0.05)");
  }

  // Add inner glow as inset shadow
  if (customization.innerGlow !== undefined) {
    const glowBlur =
      customization.innerGlowBlur !== undefined
        ? typeof customization.innerGlowBlur === "number"
          ? `${customization.innerGlowBlur}px`
          : customization.innerGlowBlur
        : "20px";
    shadows.push(`inset 0 0 ${glowBlur} ${customization.innerGlow}`);
  }

  if (shadows.length > 0) {
    styles.boxShadow = shadows.join(", ");
  }

  return styles;
}

/**
 * Generates CSS custom properties for glass customization
 * Useful for components that need to pass styles to child elements
 */
export function getGlassCSSVars(customization?: GlassCustomization): Record<string, string> {
  if (!customization) return {};

  const vars: Record<string, string> = {};

  if (customization.color || customization.transparency !== undefined) {
    let bgColor = customization.color || "oklch(100% 0 0 / 0.1)";

    if (customization.transparency !== undefined) {
      bgColor = setAlpha(bgColor, customization.transparency);
    }

    vars["--glass-bg-custom"] = bgColor;
  }

  if (customization.blur !== undefined) {
    const blurValue = typeof customization.blur === "number" ? `${customization.blur}px` : customization.blur;
    vars["--blur-custom"] = blurValue;
  }

  if (customization.outline !== undefined) {
    vars["--glass-border-custom"] = customization.outline;
  }

  if (customization.outlineWidth !== undefined) {
    const width = typeof customization.outlineWidth === "number" ? `${customization.outlineWidth}px` : customization.outlineWidth;
    vars["--glass-border-width-custom"] = width;
  }

  if (customization.shadow !== undefined) {
    vars["--glass-shadow-custom"] = customization.shadow;
  }

  if (customization.innerGlow !== undefined) {
    vars["--glass-inner-glow-custom"] = customization.innerGlow;
  }

  if (customization.innerGlowBlur !== undefined) {
    const blurValue = typeof customization.innerGlowBlur === "number" ? `${customization.innerGlowBlur}px` : customization.innerGlowBlur;
    vars["--glass-inner-glow-blur-custom"] = blurValue;
  }

  return vars;
}

import { cva } from "class-variance-authority";

/**
 * Shared hover effect variants for all Sistine components
 *
 * Effects:
 * - none: No hover effect
 * - glow: Purple glow shadow that intensifies on hover
 * - shimmer: Moving shimmer effect across the component
 * - ripple: Ripple effect that scales outward on hover
 * - lift: Subtle lift effect with shadow increase
 * - scale: Scale up slightly on hover
 */
export const hoverEffects = cva("transition-all duration-300", {
  variants: {
    hover: {
      none: "",
      glow: "shadow-lg shadow-purple-500/50 hover:shadow-xl hover:shadow-purple-500/70",
      shimmer:
        "relative overflow-hidden before:absolute before:inset-0 before:-translate-x-full before:bg-gradient-to-r before:from-transparent before:via-white/20 before:to-transparent hover:before:translate-x-full before:transition-transform before:duration-1000",
      ripple:
        "relative overflow-hidden after:absolute after:inset-0 after:scale-0 after:rounded-full after:bg-white/30 after:transition-transform after:duration-500 hover:after:scale-150",
      lift: "hover:-translate-y-1 hover:shadow-lg",
      scale: "hover:scale-105",
    },
  },
  defaultVariants: {
    hover: "none",
  },
});

export type HoverEffect = "none" | "glow" | "shimmer" | "ripple" | "lift" | "scale";

@import "tailwindcss";
@import "tw-animate-css";

@custom-variant dark (&:is(.dark *));

@theme inline {
  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --font-sans: var(--font-geist-sans);
  --font-mono: var(--font-geist-mono);
  --color-sidebar-ring: var(--sidebar-ring);
  --color-sidebar-border: var(--sidebar-border);
  --color-sidebar-accent-foreground: var(--sidebar-accent-foreground);
  --color-sidebar-accent: var(--sidebar-accent);
  --color-sidebar-primary-foreground: var(--sidebar-primary-foreground);
  --color-sidebar-primary: var(--sidebar-primary);
  --color-sidebar-foreground: var(--sidebar-foreground);
  --color-sidebar: var(--sidebar);
  --color-chart-5: var(--chart-5);
  --color-chart-4: var(--chart-4);
  --color-chart-3: var(--chart-3);
  --color-chart-2: var(--chart-2);
  --color-chart-1: var(--chart-1);
  --color-ring: var(--ring);
  --color-input: var(--input);
  --color-border: var(--border);
  --color-destructive: var(--destructive);
  --color-accent-foreground: var(--accent-foreground);
  --color-accent: var(--accent);
  --color-muted-foreground: var(--muted-foreground);
  --color-muted: var(--muted);
  --color-secondary-foreground: var(--secondary-foreground);
  --color-secondary: var(--secondary);
  --color-primary-foreground: var(--primary-foreground);
  --color-primary: var(--primary);
  --color-popover-foreground: var(--popover-foreground);
  --color-popover: var(--popover);
  --color-card-foreground: var(--card-foreground);
  --color-card: var(--card);
  --radius-sm: calc(var(--radius) - 4px);
  --radius-md: calc(var(--radius) - 2px);
  --radius-lg: var(--radius);
  --radius-xl: calc(var(--radius) + 4px);
  --shadow-glass: var(--glass-shadow);
}

:root {
  --radius: 1.25rem;
  /* Base colors - Light mode with dark text */
  --background: transparent;
  --foreground: oklch(0% 0 0); /* Level 0 — darkest extreme; AutoForeground walks the ramp at runtime */
  --card: transparent;
  --card-foreground: var(--foreground);
  --popover: transparent;
  --popover-foreground: var(--foreground);

  /* Primary colors - Light mode */
  --primary: oklch(0.5 0.2 250); /* Blue */
  --primary-foreground: oklch(0.98 0 0); /* White text on primary */

  /* Secondary colors - Light mode */
  --secondary: oklch(0.96 0 0); /* Very light gray */
  --secondary-foreground: var(--foreground);

  /* Muted colors - Light mode */
  --muted: oklch(0.85 0 0); /* Dark gray - darker shade to avoid glass effect override */
  --muted-foreground: oklch(0.14 0.04 var(--glass-tint-h)); /* Level 1 — one ramp step toward the chosen color */

  /* Accent colors - Light mode */
  --accent: oklch(0.96 0 0); /* Very light gray */
  --accent-foreground: var(--foreground);

  /* Destructive colors - WCAG AA compliant (4.5:1 contrast) */
  --destructive: oklch(0.55 0.22 25); /* Red - 4.5:1 with white */
  --destructive-foreground: oklch(0.98 0 0); /* White text on red */

  /* Border and input - WCAG AA compliant (3:1 for UI components) */
  --border: oklch(0.88 0 0); /* Light gray - 3:1 contrast */
  --input: oklch(0.88 0 0); /* Light gray - 3:1 contrast */
  --ring: oklch(0.5 0.2 250); /* Blue ring - 3:1 contrast */

  /* Chart colors - WCAG AA compliant */
  --chart-1: oklch(0.6 0.2 250); /* Blue */
  --chart-2: oklch(0.55 0.15 150); /* Green */
  --chart-3: oklch(0.5 0.2 50); /* Yellow */
  --chart-4: oklch(0.65 0.2 300); /* Purple */
  --chart-5: oklch(0.6 0.2 20); /* Orange */

  /* Sidebar colors - Light mode */
  --sidebar: oklch(0.98 0 0); /* Near white */
  --sidebar-foreground: var(--foreground);
  --sidebar-primary: oklch(0.5 0.2 250); /* Blue */
  --sidebar-primary-foreground: oklch(0.98 0 0); /* White text on primary */
  --sidebar-accent: oklch(0.15 0 0 / 0.1); /* Subtle glass overlay (≈ foreground/10), not a solid block */
  --sidebar-accent-foreground: var(--foreground);
  --sidebar-border: oklch(0.88 0 0); /* Light gray - 3:1 contrast */
  --sidebar-ring: oklch(0.5 0.2 250); /* Blue ring - 3:1 contrast */

  /* Apple-standard glassmorphism - Very subtle and refined */
  /* Glass tint — recolor ALL glass by changing these; presets set them via [data-glass-tint].
     -h = hue, -c = chroma (gradient), -a = wash alpha. The gradient alone is too sheer
     (~6–12% opacity) to show a hue, so -a paints a solid colored floor (--glass-tint-wash)
     that reads over any backdrop. Neutral keeps -a:0, so the default glass is unchanged. */
  --glass-tint-h: 250;
  --glass-tint-c: 0.018;
  --glass-tint-a: 0;
  --glass-tint-wash: oklch(72% calc(var(--glass-tint-c) * 2.5) var(--glass-tint-h) / var(--glass-tint-a));
  /* Solid accent that tracks the tint hue at a fixed vivid chroma — used by active controls (switch
     "on", slider range) so they read as the current glass hue instead of plain black/white. */
  --glass-accent: oklch(0.6 0.15 var(--glass-tint-h));
  /* Opaque-ish floor for read-through overlays (menus/tooltips/toasts) so they stay legible. */
  --glass-solid-bg: oklch(99% 0 0 / 0.65);
  /* Opaque glass — a fully solid, faintly tinted floor (no see-through) for the "opaque" style. */
  --glass-opaque-bg: oklch(95% calc(var(--glass-tint-c) * 1.5) var(--glass-tint-h));
  /* Hue/chroma come from the tint vars; chroma is scaled per stop so the highlights stay
     glassy (low chroma) and the body carries the color. Alphas are unchanged. */
  --glass-bg: linear-gradient(
    135deg,
    oklch(100% calc(var(--glass-tint-c) * 0.3) var(--glass-tint-h) / 0.15) 0%,
    oklch(99% calc(var(--glass-tint-c) * 0.5) var(--glass-tint-h) / 0.12) 25%,
    oklch(97% calc(var(--glass-tint-c) * 1) var(--glass-tint-h) / 0.13) 50%,
    oklch(99% calc(var(--glass-tint-c) * 0.5) var(--glass-tint-h) / 0.11) 75%,
    oklch(95% calc(var(--glass-tint-c) * 1.3) var(--glass-tint-h) / 0.12) 100%
  );
  /* Very subtle white border - Apple standard */
  --glass-border: oklch(100% calc(var(--glass-tint-c) * 0.5) var(--glass-tint-h) / 0.12);
  /* Minimal shadows with subtle inner glow - Apple standard */
  --glass-shadow:
    0 4px 16px oklch(0% 0 0 / 0.08), 0 1px 4px oklch(0% 0 0 / 0.04), 0 0 0 0.5px oklch(100% 0 0 / 0.08) inset, 0 0 12px oklch(100% 0 0 / 0.1) inset;
  --glass-shadow-lg:
    0 8px 32px oklch(0% 0 0 / 0.1), 0 2px 8px oklch(0% 0 0 / 0.06), 0 0 0 0.5px oklch(100% 0 0 / 0.1) inset, 0 0 20px oklch(100% 0 0 / 0.12) inset;
  --glass-shadow-sm:
    0 2px 8px oklch(0% 0 0 / 0.06), 0 1px 2px oklch(0% 0 0 / 0.03), 0 0 0 0.5px oklch(100% 0 0 / 0.06) inset, 0 0 8px oklch(100% 0 0 / 0.08) inset;
  --gradient: linear-gradient(135deg, oklch(62.6846% 0.23254 303.9) 0%, oklch(62.3083% 0.18801 259.815) 100%);
  /* Apple-standard blur values - moderate blur */
  --blur: 10px;
  --blur-sm: 4px;
  --blur-lg: 20px;

  /* Frosted glass variant - Enhanced opacity and stronger blur */
  --glass-frosted-bg: linear-gradient(
    135deg,
    oklch(100% calc(var(--glass-tint-c) * 0.3) var(--glass-tint-h) / 0.25) 0%,
    oklch(99% calc(var(--glass-tint-c) * 0.5) var(--glass-tint-h) / 0.22) 25%,
    oklch(97% calc(var(--glass-tint-c) * 1) var(--glass-tint-h) / 0.23) 50%,
    oklch(99% calc(var(--glass-tint-c) * 0.5) var(--glass-tint-h) / 0.21) 75%,
    oklch(95% calc(var(--glass-tint-c) * 1.3) var(--glass-tint-h) / 0.22) 100%
  );
  --glass-frosted-border: oklch(100% 0 0 / 0.3);
  --glass-frosted-shadow:
    0 8px 32px oklch(0% 0 0 / 0.12), 0 2px 8px oklch(0% 0 0 / 0.08), 0 0 0 0.5px oklch(100% 0 0 / 0.15) inset, 0 0 20px oklch(100% 0 0 / 0.18) inset;
  --blur-frosted: 25px;

  /* Fluted glass variant - Vertical ridges pattern */
  --glass-fluted-pattern: repeating-linear-gradient(
    90deg,
    oklch(100% 0 0 / 0.08) 0px,
    oklch(100% 0 0 / 0.15) 4px,
    oklch(100% 0 0 / 0.08) 8px,
    oklch(100% 0 0 / 0.02) 10px,
    oklch(100% 0 0 / 0.08) 12px
  );

  /* Crystal glass variant - Clear glass with highlights and glow */
  --glass-crystal-bg: oklch(100% calc(var(--glass-tint-c) * 0.6) var(--glass-tint-h) / 0.3);
  --glass-crystal-border: oklch(100% calc(var(--glass-tint-c) * 0.6) var(--glass-tint-h) / 0.3);
  --glass-crystal-shadow: 0 0 20px oklch(0% 0 0 / 0.2), 0 0 30px oklch(100% 0 0 / 0.1);
  --glass-crystal-shadow-hover: 0 0 25px oklch(0% 0 0 / 0.3), 0 0 35px oklch(100% 0 0 / 0.15);
  --blur-crystal: 2px;
}

.dark {
  /* Apple-standard glassmorphism for dark mode - Very subtle and refined */
  /* Very low opacity for Apple's standard glass effect in dark mode */
  /* Deeper wash lightness so the tint reads as colored glass over dark backdrops. */
  --glass-tint-wash: oklch(58% calc(var(--glass-tint-c) * 2.5) var(--glass-tint-h) / var(--glass-tint-a));
  /* Lighter accent so the tint hue pops on dark surfaces (see :root for the rationale). */
  --glass-accent: oklch(0.68 0.14 var(--glass-tint-h));
  --glass-solid-bg: oklch(18% 0 0 / 0.65);
  /* L lifted from 22% (less extreme light↔dark switch) + chroma kept low so warm hues like amber
     stay in-gamut instead of hard-clipping to rust. */
  --glass-opaque-bg: oklch(32% calc(var(--glass-tint-c) * 0.9) var(--glass-tint-h));
  --glass-bg: linear-gradient(
    135deg,
    oklch(100% calc(var(--glass-tint-c) * 0.3) var(--glass-tint-h) / 0.08) 0%,
    oklch(99% calc(var(--glass-tint-c) * 0.5) var(--glass-tint-h) / 0.06) 25%,
    oklch(97% calc(var(--glass-tint-c) * 1) var(--glass-tint-h) / 0.07) 50%,
    oklch(99% calc(var(--glass-tint-c) * 0.5) var(--glass-tint-h) / 0.05) 75%,
    oklch(95% calc(var(--glass-tint-c) * 1.3) var(--glass-tint-h) / 0.06) 100%
  );
  /* Very subtle white border - Apple standard */
  --glass-border: oklch(100% calc(var(--glass-tint-c) * 0.5) var(--glass-tint-h) / 0.15);
  /* Minimal shadows with subtle inner glow - Apple standard for dark mode */
  --glass-shadow:
    0 4px 16px oklch(0% 0 0 / 0.3), 0 1px 4px oklch(0% 0 0 / 0.15), 0 0 0 0.5px oklch(100% 0 0 / 0.12) inset, 0 0 12px oklch(100% 0 0 / 0.15) inset;
  --glass-shadow-lg:
    0 8px 32px oklch(0% 0 0 / 0.4), 0 2px 8px oklch(0% 0 0 / 0.2), 0 0 0 0.5px oklch(100% 0 0 / 0.15) inset, 0 0 20px oklch(100% 0 0 / 0.18) inset;
  --glass-shadow-sm:
    0 2px 8px oklch(0% 0 0 / 0.25), 0 1px 2px oklch(0% 0 0 / 0.12), 0 0 0 0.5px oklch(100% 0 0 / 0.1) inset, 0 0 8px oklch(100% 0 0 / 0.12) inset;

  /* Frosted glass variant - Enhanced opacity and stronger blur for dark mode */
  --glass-frosted-bg: linear-gradient(
    135deg,
    oklch(100% calc(var(--glass-tint-c) * 0.3) var(--glass-tint-h) / 0.15) 0%,
    oklch(99% calc(var(--glass-tint-c) * 0.5) var(--glass-tint-h) / 0.12) 25%,
    oklch(97% calc(var(--glass-tint-c) * 1) var(--glass-tint-h) / 0.13) 50%,
    oklch(99% calc(var(--glass-tint-c) * 0.5) var(--glass-tint-h) / 0.11) 75%,
    oklch(95% calc(var(--glass-tint-c) * 1.3) var(--glass-tint-h) / 0.12) 100%
  );
  --glass-frosted-border: oklch(100% 0 0 / 0.25);
  --glass-frosted-shadow:
    0 8px 32px oklch(0% 0 0 / 0.5), 0 2px 8px oklch(0% 0 0 / 0.3), 0 0 0 0.5px oklch(100% 0 0 / 0.2) inset, 0 0 20px oklch(100% 0 0 / 0.22) inset;

  /* Fluted glass variant - Vertical ridges pattern for dark mode */
  --glass-fluted-pattern: repeating-linear-gradient(
    90deg,
    oklch(100% 0 0 / 0.05) 0px,
    oklch(100% 0 0 / 0.12) 4px,
    oklch(100% 0 0 / 0.05) 8px,
    oklch(100% 0 0 / 0.01) 10px,
    oklch(100% 0 0 / 0.05) 12px
  );

  /* Crystal glass variant - Clear glass with highlights and glow for dark mode */
  --glass-crystal-bg: oklch(100% calc(var(--glass-tint-c) * 0.6) var(--glass-tint-h) / 0.1);
  --glass-crystal-border: oklch(100% calc(var(--glass-tint-c) * 0.6) var(--glass-tint-h) / 0.3);
  --glass-crystal-shadow: 0 0 20px oklch(0% 0 0 / 0.4), 0 0 30px oklch(100% 0 0 / 0.15);
  --glass-crystal-shadow-hover: 0 0 25px oklch(0% 0 0 / 0.5), 0 0 35px oklch(100% 0 0 / 0.2);

  /* Base colors - Apple-style white text */
  --background: transparent;
  --foreground: oklch(100% 0 0); /* Level 0 — lightest extreme; AutoForeground walks the ramp at runtime */
  --card: transparent;
  --card-foreground: var(--foreground);
  --popover: transparent;
  --popover-foreground: var(--foreground);

  /* Primary colors - Apple-style white text */
  --primary: oklch(0.56 0.16 250); /* Blue — deepened from L0.7 so white text clears APCA Lc ~76 (was 57) */
  --primary-foreground: oklch(1 0 0); /* White - Apple-style */

  /* Secondary colors - Apple-style white text */
  --secondary: oklch(0.25 0 0); /* Dark gray */
  --secondary-foreground: var(--foreground);

  /* Muted colors - Apple-style white text */
  --muted: oklch(0.18 0 0); /* Darker gray - darker shade to avoid glass effect override */
  --muted-foreground: oklch(0.89 0.04 var(--glass-tint-h)); /* Level 1 — one ramp step toward the chosen color */

  /* Accent colors - Apple-style white text */
  --accent: oklch(0.25 0 0); /* Dark gray */
  --accent-foreground: var(--foreground);

  /* Destructive colors - WCAG AA compliant (4.5:1 contrast) */
  --destructive: oklch(0.65 0.22 25); /* Light red - 4.5:1 with dark background */
  --destructive-foreground: oklch(1 0 0); /* White text on red — APCA Lc ~67 (near-black was Lc 42) */

  /* Border and input - WCAG AA compliant (3:1 for UI components) */
  --border: oklch(0.3 0 0); /* Medium gray - 3:1 contrast */
  --input: oklch(0.25 0 0); /* Dark gray - 3:1 contrast */
  --ring: oklch(0.6 0.2 250); /* Light blue ring - 3:1 contrast */

  /* Chart colors - WCAG AA compliant */
  --chart-1: oklch(0.65 0.2 250); /* Light blue */
  --chart-2: oklch(0.7 0.15 150); /* Light green */
  --chart-3: oklch(0.75 0.2 50); /* Light yellow */
  --chart-4: oklch(0.7 0.2 300); /* Light purple */
  --chart-5: oklch(0.68 0.2 20); /* Light orange */

  /* Sidebar colors - Apple-style white text */
  --sidebar: oklch(0.18 0 0); /* Dark gray */
  --sidebar-foreground: var(--foreground);
  --sidebar-primary: oklch(0.56 0.16 250); /* Match --primary; white text clears APCA */
  --sidebar-primary-foreground: oklch(1 0 0); /* White - Apple-style */
  --sidebar-accent: oklch(1 0 0 / 0.1); /* Subtle glass overlay (≈ foreground/10), not a solid block */
  --sidebar-accent-foreground: var(--foreground);
  --sidebar-border: oklch(0.3 0 0); /* Medium gray - 3:1 contrast */
  --sidebar-ring: oklch(0.6 0.2 250); /* Light blue ring - 3:1 contrast */
}

@layer base {
  * {
    @apply border-border outline-ring/50;
    scrollbar-width: thin;
    scrollbar-color: color-mix(in oklch, var(--foreground) 22%, transparent) transparent;
  }
  body {
    /* Text defaults to the APCA-picked --auto-fg (set on <html> by AutoForeground on theme/tint
       change), falling back to the neutral --foreground when it isn't set. */
    color: var(--auto-fg, var(--foreground));
    background-color: transparent;
  }
  /* Thin, glass-friendly scrollbars (replaces the chunky native bar) */
  ::-webkit-scrollbar {
    width: 8px;
    height: 8px;
  }
  ::-webkit-scrollbar-track {
    background: transparent;
  }
  ::-webkit-scrollbar-thumb {
    background-color: color-mix(in oklch, var(--foreground) 22%, transparent);
    border-radius: 9999px;
  }
  ::-webkit-scrollbar-thumb:hover {
    background-color: color-mix(in oklch, var(--foreground) 38%, transparent);
  }
}

/* ── Glass surface utilities ───────────────────────────────────────────────
   Each glass variant is configured here (the recipe); its values live in the
   --glass-* / --blur* tokens in :root/.dark. Tailwind v4 @utility blocks are
   top-level. Components reference these by name — glass-bg, glass-surface,
   glass-frosted, glass-fluted, glass-crystal — with no inline blur/border/shadow. */

/* Borderless base — Apple-standard subtle glass (card, button, etc.) */
@utility glass-bg {
  background-image: var(--glass-bg);
  background-color: var(--glass-tint-wash);
  backdrop-filter: blur(var(--blur)) saturate(180%);
  -webkit-backdrop-filter: blur(var(--blur)) saturate(180%);
  box-shadow: var(--glass-shadow);
}

/* Bordered glass surface — the standard glass variant for panels & overlays */
@utility glass-surface {
  background-image: var(--glass-bg);
  background-color: var(--glass-tint-wash);
  backdrop-filter: blur(var(--blur)) saturate(180%);
  -webkit-backdrop-filter: blur(var(--blur)) saturate(180%);
  border: 1px solid var(--glass-border);
  box-shadow: var(--glass-shadow);
}

/* Compact frost — smaller blur + shadow for small controls (inputs, badges). */
@utility glass-surface-sm {
  background-image: var(--glass-bg);
  background-color: var(--glass-tint-wash);
  backdrop-filter: blur(var(--blur-sm)) saturate(180%);
  -webkit-backdrop-filter: blur(var(--blur-sm)) saturate(180%);
  border: 1px solid var(--glass-border);
  box-shadow: var(--glass-shadow-sm);
}

/* Deep frost — larger blur + shadow for big overlays (dialogs, sheets). */
@utility glass-surface-lg {
  background-image: var(--glass-bg);
  background-color: var(--glass-tint-wash);
  backdrop-filter: blur(var(--blur-lg)) saturate(180%);
  -webkit-backdrop-filter: blur(var(--blur-lg)) saturate(180%);
  border: 1px solid var(--glass-border);
  box-shadow: var(--glass-shadow-lg);
}

/* Opaque glass — a near-solid neutral floor (--glass-solid-bg) + the tint wash + the glass
   sheen, so overlays you read through (tooltips, menus, toasts) stay legible and still tint.
   Raise --glass-solid-bg's alpha to be more solid, lower it to be more see-through. */
@utility glass-solid {
  background-image: var(--glass-bg), linear-gradient(var(--glass-tint-wash), var(--glass-tint-wash));
  background-color: var(--glass-solid-bg);
  backdrop-filter: blur(var(--blur)) saturate(180%);
  -webkit-backdrop-filter: blur(var(--blur)) saturate(180%);
  border: 1px solid var(--glass-border);
  box-shadow: var(--glass-shadow);
}

/* Opaque — solid (no see-through) but still glassy: an opaque tinted floor under the glass sheen,
   with the glass border + shadow, and NO backdrop blur (nothing to blur through). Drives the
   "opaque" style + the matching component variant. */
@utility glass-opaque {
  background-image: var(--glass-bg);
  background-color: var(--glass-opaque-bg);
  border: 1px solid var(--glass-border);
  box-shadow: var(--glass-shadow);
}

/* Frosted — enhanced blur + higher opacity */
@utility glass-frosted {
  background-image: var(--glass-frosted-bg) !important;
  background-color: var(--glass-tint-wash) !important;
  backdrop-filter: blur(var(--blur-frosted)) saturate(200%) !important;
  -webkit-backdrop-filter: blur(var(--blur-frosted)) saturate(200%) !important;
  border: 0.5px solid var(--glass-frosted-border) !important;
  box-shadow: var(--glass-frosted-shadow) !important;
}

/* Fluted — vertical ridges over standard glass */
@utility glass-fluted {
  background-image: var(--glass-fluted-pattern), var(--glass-bg) !important;
  background-color: var(--glass-tint-wash) !important;
  backdrop-filter: blur(var(--blur)) saturate(180%) !important;
  -webkit-backdrop-filter: blur(var(--blur)) saturate(180%) !important;
  border: 0.5px solid var(--glass-border) !important;
  box-shadow: var(--glass-shadow) !important;
}

/* Crystal — clear glass with highlight sheen and glow */
@utility glass-crystal {
  position: relative;
  background-color: var(--glass-crystal-bg) !important;
  background-image:
    linear-gradient(to bottom right, oklch(100% 0 0 / 0.15), transparent 50%), linear-gradient(var(--glass-tint-wash), var(--glass-tint-wash)) !important;
  background-size: 200% 200% !important;
  backdrop-filter: blur(var(--blur-crystal)) !important;
  -webkit-backdrop-filter: blur(var(--blur-crystal)) !important;
  border: 1px solid var(--glass-crystal-border) !important;
  box-shadow: var(--glass-crystal-shadow) !important;
  transition: all 0.3s ease !important;

  &::before {
    content: "";
    position: absolute;
    inset: 0;
    border-radius: inherit;
    background: linear-gradient(to bottom, oklch(100% 0 0 / 0.4), transparent);
    opacity: 0.7;
    pointer-events: none;
    height: 30%;
  }

  &::after {
    content: "";
    position: absolute;
    inset: 0;
    border-radius: inherit;
    background: radial-gradient(circle at 50% 120%, oklch(100% 0 0 / 0.2), transparent 70%);
    opacity: 0.8;
    pointer-events: none;
  }

  &:hover {
    box-shadow: var(--glass-crystal-shadow-hover) !important;
    background-position: 100% 100% !important;
  }
}

/* Keep react-day-picker from painting over the glass background */
@layer utilities {
  .glass-bg[class*="rdp"],
  .glass-bg .rdp,
  .glass-bg .rdp-month {
    background-color: transparent !important;
  }
}

/* ── Site-wide glass style ──────────────────────────────────────────────────
   Set data-glass on <html> (frosted | fluted | crystal) to re-skin the DEFAULT
   glass surfaces (glass-bg / glass-surface / -sm / -lg) as that style, so a whole
   page can preview each look. Menus (glass-solid) stay opaque for legibility, and
   explicit glass-frosted/fluted/crystal variants are untouched. Plain rules
   (outside @layer) so they win over the @utility definitions. */
[data-glass="frosted"] .glass-bg,
[data-glass="frosted"] .glass-surface,
[data-glass="frosted"] .glass-surface-sm,
[data-glass="frosted"] .glass-surface-lg {
  background-image: var(--glass-frosted-bg) !important;
  background-color: var(--glass-tint-wash) !important;
  backdrop-filter: blur(var(--blur-frosted)) saturate(200%) !important;
  -webkit-backdrop-filter: blur(var(--blur-frosted)) saturate(200%) !important;
  box-shadow: var(--glass-frosted-shadow) !important;
}
/* border-color only on bordered surfaces — NOT .glass-bg — so a destructive control's red
   outline (glass-bg + border-destructive) survives the style switch. */
[data-glass="frosted"] .glass-surface,
[data-glass="frosted"] .glass-surface-sm,
[data-glass="frosted"] .glass-surface-lg {
  border-color: var(--glass-frosted-border) !important;
}

[data-glass="fluted"] .glass-bg,
[data-glass="fluted"] .glass-surface,
[data-glass="fluted"] .glass-surface-sm,
[data-glass="fluted"] .glass-surface-lg {
  background-image: var(--glass-fluted-pattern), var(--glass-bg) !important;
  background-color: var(--glass-tint-wash) !important;
}
[data-glass="fluted"] .glass-surface,
[data-glass="fluted"] .glass-surface-sm,
[data-glass="fluted"] .glass-surface-lg {
  border-color: var(--glass-border) !important;
}

[data-glass="crystal"] .glass-bg,
[data-glass="crystal"] .glass-surface,
[data-glass="crystal"] .glass-surface-sm,
[data-glass="crystal"] .glass-surface-lg {
  background-color: var(--glass-crystal-bg) !important;
  /* Sheen + glow baked into the background so it matches the crystal ::before/::after
     without forcing position:relative (which would break sticky/fixed surfaces). The wash
     is the bottom layer so the tint shows through the (mostly-transparent) sheen above it. */
  background-image:
    linear-gradient(to bottom, oklch(100% 0 0 / 0.4), transparent 30%), radial-gradient(circle at 50% 120%, oklch(100% 0 0 / 0.2), transparent 70%),
    linear-gradient(to bottom right, oklch(100% 0 0 / 0.15), transparent 50%), linear-gradient(var(--glass-tint-wash), var(--glass-tint-wash)) !important;
  backdrop-filter: blur(var(--blur-crystal)) !important;
  -webkit-backdrop-filter: blur(var(--blur-crystal)) !important;
  box-shadow: var(--glass-crystal-shadow) !important;
}
[data-glass="crystal"] .glass-surface,
[data-glass="crystal"] .glass-surface-sm,
[data-glass="crystal"] .glass-surface-lg {
  border-color: var(--glass-crystal-border) !important;
}

/* Overlays (glass-solid) follow the style switcher too, but keep their opaque floor
   (--glass-solid-bg) so menus stay legible in every style. */
[data-glass="frosted"] .glass-solid {
  background-image: var(--glass-frosted-bg), linear-gradient(var(--glass-tint-wash), var(--glass-tint-wash)) !important;
  background-color: var(--glass-solid-bg) !important;
  backdrop-filter: blur(var(--blur-frosted)) saturate(200%) !important;
  -webkit-backdrop-filter: blur(var(--blur-frosted)) saturate(200%) !important;
  border-color: var(--glass-frosted-border) !important;
  box-shadow: var(--glass-frosted-shadow) !important;
}
[data-glass="fluted"] .glass-solid {
  background-image: var(--glass-fluted-pattern), var(--glass-bg), linear-gradient(var(--glass-tint-wash), var(--glass-tint-wash)) !important;
  background-color: var(--glass-solid-bg) !important;
  border-color: var(--glass-border) !important;
}
[data-glass="crystal"] .glass-solid {
  background-image:
    linear-gradient(to bottom, oklch(100% 0 0 / 0.4), transparent 30%), radial-gradient(circle at 50% 120%, oklch(100% 0 0 / 0.2), transparent 70%),
    linear-gradient(to bottom right, oklch(100% 0 0 / 0.15), transparent 50%), linear-gradient(var(--glass-tint-wash), var(--glass-tint-wash)) !important;
  background-color: var(--glass-solid-bg) !important;
  backdrop-filter: blur(var(--blur-crystal)) !important;
  -webkit-backdrop-filter: blur(var(--blur-crystal)) !important;
  border-color: var(--glass-crystal-border) !important;
  box-shadow: var(--glass-crystal-shadow) !important;
}

/* Opaque — re-skin the default glass surfaces as a fully solid (no see-through) tinted panel.
   Drops the backdrop blur (it's opaque) and overlays (glass-solid) go fully opaque too. */
[data-glass="opaque"] .glass-bg,
[data-glass="opaque"] .glass-surface,
[data-glass="opaque"] .glass-surface-sm,
[data-glass="opaque"] .glass-surface-lg,
[data-glass="opaque"] .glass-solid {
  background-image: var(--glass-bg) !important;
  background-color: var(--glass-opaque-bg) !important;
  backdrop-filter: none !important;
  -webkit-backdrop-filter: none !important;
  box-shadow: var(--glass-shadow) !important;
}
[data-glass="opaque"] .glass-surface,
[data-glass="opaque"] .glass-surface-sm,
[data-glass="opaque"] .glass-surface-lg,
[data-glass="opaque"] .glass-solid {
  border-color: var(--glass-border) !important;
}

/* ── Glass tint presets ─────────────────────────────────────────────────────
   Set data-glass-tint on <html> to recolor the glass. Most presets just move the
   tint hue/chroma; "sistine" is a bespoke multi-hue fresco (gilded gold →
   terracotta flesh tones → azure sky), echoing the Sistine Chapel ceiling. */
[data-glass-tint="sapphire"] {
  --glass-tint-h: 255;
  --glass-tint-c: 0.07;
  --glass-tint-a: 0.15;
}
[data-glass-tint="emerald"] {
  --glass-tint-h: 158;
  --glass-tint-c: 0.07;
  --glass-tint-a: 0.15;
}
[data-glass-tint="amethyst"] {
  --glass-tint-h: 300;
  --glass-tint-c: 0.07;
  --glass-tint-a: 0.15;
}
[data-glass-tint="rose"] {
  --glass-tint-h: 8;
  --glass-tint-c: 0.07;
  --glass-tint-a: 0.15;
}
[data-glass-tint="amber"] {
  --glass-tint-h: 75;
  --glass-tint-c: 0.07;
  --glass-tint-a: 0.16;
}

/* Sistine — the signature: a painterly fresco gradient. Border + crystal pick up the
   warm gold via the tint vars; the surfaces use the bespoke multi-hue gradient. */
[data-glass-tint="sistine"] {
  /* Gilded fresco — a coherent warm sweep (gold → amber → terracotta). Earlier this was a
     5-hue gold→azure→rose blend, but opposing hues averaged to greige; staying in the warm
     band at higher chroma reads as gold leaf instead of mud. */
  --glass-tint-h: 82;
  --glass-tint-c: 0.1;
  --glass-tint-a: 0.16;
  --glass-bg: linear-gradient(
    135deg,
    oklch(94% 0.09 95 / 0.34) 0%,
    oklch(90% 0.11 78 / 0.3) 38%,
    oklch(87% 0.11 58 / 0.3) 72%,
    oklch(84% 0.105 42 / 0.32) 100%
  );
  --glass-frosted-bg: linear-gradient(
    135deg,
    oklch(94% 0.09 95 / 0.46) 0%,
    oklch(90% 0.11 78 / 0.42) 38%,
    oklch(87% 0.11 58 / 0.42) 72%,
    oklch(84% 0.105 42 / 0.44) 100%
  );
}
.dark[data-glass-tint="sistine"] {
  --glass-bg: linear-gradient(
    135deg,
    oklch(90% 0.09 95 / 0.22) 0%,
    oklch(86% 0.11 78 / 0.2) 38%,
    oklch(83% 0.11 58 / 0.2) 72%,
    oklch(80% 0.105 42 / 0.22) 100%
  );
  --glass-frosted-bg: linear-gradient(
    135deg,
    oklch(90% 0.09 95 / 0.32) 0%,
    oklch(86% 0.11 78 / 0.3) 38%,
    oklch(83% 0.11 58 / 0.3) 72%,
    oklch(80% 0.105 42 / 0.32) 100%
  );
}

@keyframes shimmer {
  0% {
    transform: translateX(-100%);
  }
  100% {
    transform: translateX(100%);
  }
}

/* Sonner Toast Notifications - Glass Effect Overrides */
[data-sonner-toast] {
  /* Glass gradient layered over a mostly-opaque surface so toast text stays legible.
     Lower the popover % to make toasts more see-through, raise it to make them more solid. */
  background: var(--glass-bg), color-mix(in oklch, var(--popover) 78%, transparent) !important;
  backdrop-filter: blur(var(--blur)) !important;
  -webkit-backdrop-filter: blur(var(--blur)) !important;
  border: 1px solid var(--glass-border) !important;
  box-shadow: var(--glass-shadow-lg) !important;
  color: var(--foreground) !important;
}

[data-sonner-toast][data-type="success"] {
  border-color: oklch(72.2746% 0.19201 149.579 / 0.3) !important;
}

[data-sonner-toast][data-type="error"] {
  border-color: oklch(63.6834% 0.20785 25.3313 / 0.3) !important;
}

[data-sonner-toast][data-type="warning"] {
  border-color: oklch(79.5243% 0.16167 86.0468 / 0.3) !important;
}

[data-sonner-toast][data-type="info"] {
  border-color: oklch(62.3083% 0.18801 259.815 / 0.3) !important;
}

/* Toast description text */
[data-sonner-toast] [data-description] {
  color: var(--muted-foreground) !important;
}

/* Toast action buttons - Glass styled */
[data-sonner-toast] [data-button] {
  background: var(--glass-bg) !important;
  backdrop-filter: blur(var(--blur-sm)) !important;
  -webkit-backdrop-filter: blur(var(--blur-sm)) !important;
  border: 1px solid var(--glass-border) !important;
  color: var(--foreground) !important;
  transition: opacity 0.2s ease !important;
}

[data-sonner-toast] [data-button]:hover {
  opacity: 0.9 !important;
}

/* Toast cancel button */
[data-sonner-toast] [data-cancel] {
  background: var(--glass-bg) !important;
  backdrop-filter: blur(var(--blur-sm)) !important;
  -webkit-backdrop-filter: blur(var(--blur-sm)) !important;
  border: 1px solid var(--glass-border) !important;
  color: var(--muted-foreground) !important;
}

[data-sonner-toast] [data-cancel]:hover {
  opacity: 0.9 !important;
}

/* Toast close button */
[data-sonner-toast] [data-close-button] {
  background: var(--glass-bg) !important;
  backdrop-filter: blur(var(--blur-sm)) !important;
  -webkit-backdrop-filter: blur(var(--blur-sm)) !important;
  border: 1px solid var(--glass-border) !important;
  color: var(--foreground) !important;
}

[data-sonner-toast] [data-close-button]:hover {
  opacity: 0.9 !important;
}

